struct node {
	ll id, dp;
	bool operator<(const node& a)const {
		return a.dp < dp; // 小根堆
	}
};
struct node2 {
	ll s, k, sum;
	map<int, pll> sons; // { son 节点编号, { cnt 边个数, val 节点贡献 } }
};
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<node2>(n + 1);
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n) {
		ll s, k; cin >> s >> k;
		int r; cin >> r;
		var mp = map<int, pll>();
		fa(_, 1, r) {
			int x; cin >> x;
			g[x].pb(i); // 反向边：x 作为子节点，父亲是 i
			mp[x].px++; // 记录 i 分裂出 x 的次数
		}
		a[i] = { s,k,0,mp };
	}
	fa(i, 1, n) {
		sort(all(g[i]));
		g[i].erase(unique(all(g[i])), g[i].end()); // 反向边去重
	}

	var f = vector<ll>(n + 1);
	var Q = priority_queue<node>();
	fa(i, 1, n) {
		f[i] = a[i].k; // 初始化为法术攻击代价
		Q.push({ i, f[i] });
	}
	fa(i, 1, n) {
		for (var& [son, p] : a[i].sons) {
			var& [cnt, val] = p;
			val = f[son] * cnt; // 计算初始贡献 = cnt * f[son]
			a[i].sum += val;
		}
	}

	while (Q.size()) {
		var[now, dp] = Q.top();
		Q.pop();
		if (dp > f[now]) continue; // 过期元素跳过
		for (int to : g[now]) {
			// 更新父节点 to 的 sum
			a[to].sum -= a[to].sons[now].py;                   // 减去旧贡献 (py 即 val)
			a[to].sons[now].py = f[now] * a[to].sons[now].px;  // 新贡献 = f[now] * cnt
			a[to].sum += a[to].sons[now].py;

			// 若普通攻击更优则更新 f[to]
			if (f[to] > a[to].sum + a[to].s) {
				f[to] = a[to].sum + a[to].s;
				Q.push({ to, f[to] });
			}
		}
	}

	cout << f[1] << endl; // 杀死 1 号怪兽的最小体力
	return;
}
